using CollegeManagementSystem.Data;using CollegeManagementSystem.Data.Entities;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;namespace CollegeManagementSystem.Controllers;[Route("api/[controller]")][ApiController]public class CoursesController(AppDbContext db) : ControllerBase{//     private AppDbContext _db;////     public CoursesController(AppDbContext db)//     {//         this._db = db;//     }    [HttpPost("/add")]    public IActionResult AddCourse(Course course)    {        db.Courses.Add(course);        db.SaveChanges();        return Ok("Course Added");    }    [HttpGet("/get")]    public async Task<IActionResult> GetAllCourses()    {        var allCourses = await db.Courses.ToListAsync();        return Ok(allCourses);    }}